const pptxgen = require("pptxgenjs");

const pres = new pptxgen();
pres.layout = 'LAYOUT_16x9';
pres.title = 'EX Intelligence 체계 구축';

// ─── Design tokens (EXG team style) ───
const C = {
  black:    "1A1A1A",
  darkGray: "444444",
  midGray:  "888888",
  lightGray:"E8E8E8",
  offWhite: "F5F5F5",
  white:    "FFFFFF",
  olive:    "4A7C59",   // accent green (bold keywords)
  red:      "CC0000",   // LG red (extreme emphasis)
  barColor: "222222",   // left vertical bar
  bgSlide:  "FFFFFF",
};

const FONT = {
  title:   "Malgun Gothic",
  body:    "Malgun Gothic",
};

// ─── Helpers ──────────────────────────
function slideHeader(slide, num, title, subtitle) {
  // Left vertical bar
  slide.addShape(pres.shapes.RECTANGLE, {
    x: 0.35, y: 0.28, w: 0.07, h: 0.55,
    fill: { color: C.barColor }, line: { color: C.barColor }
  });
  // Title
  slide.addText(title, {
    x: 0.50, y: 0.22, w: 8.8, h: 0.45,
    fontFace: FONT.title, fontSize: 18, bold: true,
    color: C.black, valign: "middle", margin: 0
  });
  // Subtitle
  if (subtitle) {
    slide.addText(subtitle, {
      x: 0.50, y: 0.72, w: 9.3, h: 0.30,
      fontFace: FONT.body, fontSize: 11, italic: true,
      color: C.darkGray, valign: "middle", margin: 0
    });
  }
  // Horizontal divider
  slide.addShape(pres.shapes.LINE, {
    x: 0.35, y: 1.07, w: 9.3, h: 0,
    line: { color: C.darkGray, width: 0.8 }
  });
  // Slide number
  slide.addText(`${num} / 8`, {
    x: 8.8, y: 5.30, w: 1.0, h: 0.22,
    fontFace: FONT.body, fontSize: 9, color: C.midGray,
    align: "right", margin: 0
  });
}

function blackBox(slide, x, y, w, h, text, fontSize = 9.5) {
  slide.addShape(pres.shapes.RECTANGLE, {
    x, y, w, h, fill: { color: C.black }, line: { color: C.black }
  });
  slide.addText(text, {
    x: x + 0.05, y, w: w - 0.1, h,
    fontFace: FONT.body, fontSize, color: C.white,
    bold: true, valign: "middle", align: "center", margin: 0
  });
}

function sectionLabel(slide, x, y, w, h, text) {
  slide.addShape(pres.shapes.RECTANGLE, {
    x, y, w, h, fill: { color: C.lightGray }, line: { color: C.lightGray }
  });
  slide.addText(text, {
    x, y, w, h,
    fontFace: FONT.body, fontSize: 9.5, bold: true,
    color: C.black, valign: "middle", align: "center", margin: 0
  });
}

function appendixBadge(slide, label) {
  slide.addShape(pres.shapes.RECTANGLE, {
    x: 8.5, y: 0.12, w: 1.3, h: 0.3,
    fill: { color: C.darkGray }, line: { color: C.darkGray }
  });
  slide.addText(label, {
    x: 8.5, y: 0.12, w: 1.3, h: 0.3,
    fontFace: FONT.body, fontSize: 8.5, color: C.white,
    bold: true, align: "center", valign: "middle", margin: 0
  });
}

function backLink(slide) {
  slide.addText("▶ 본문으로 돌아가기", {
    x: 0.35, y: 5.30, w: 2.5, h: 0.22,
    fontFace: FONT.body, fontSize: 8.5, color: C.midGray, margin: 0
  });
}

// ══════════════════════════════════════
// SLIDE 1 — 표지
// ══════════════════════════════════════
{
  const s = pres.addSlide();
  s.background = { color: "1A1A1A" };

  s.addText("『 EX Intelligence 』 체계 구축", {
    x: 0.8, y: 1.6, w: 8.4, h: 0.9,
    fontFace: FONT.title, fontSize: 32, bold: true,
    color: C.white, align: "center", valign: "middle"
  });
  s.addText('"구성원 신호를 조직 성과로 전환하는 AX 기반 상시 진단 체계"', {
    x: 0.8, y: 2.55, w: 8.4, h: 0.4,
    fontFace: FONT.body, fontSize: 14, italic: true,
    color: "BBBBBB", align: "center", valign: "middle"
  });
  // Divider
  s.addShape(pres.shapes.LINE, {
    x: 2.5, y: 3.1, w: 5.0, h: 0,
    line: { color: "444444", width: 0.8 }
  });
  // TOC
  const toc = [
    "① 추진배경",
    "② EX Intelligence 정의 및 지향점",
    "③ 작동원리",
    "④ Health Check Process",
    "⑤ Communication & Solution 제공",
    "⑥ 구성원 참여 촉진 방안",
    "⑦ 시스템 구체화 및 구현 방안",
  ];
  s.addText(toc.map((t, i) => ({
    text: t, options: { breakLine: i < toc.length - 1 }
  })), {
    x: 2.8, y: 3.25, w: 4.4, h: 1.8,
    fontFace: FONT.body, fontSize: 11, color: "CCCCCC",
    align: "left", valign: "top", lineSpacingMultiple: 1.5
  });
  // Footer
  s.addText("PRI HR 실 / EXG팀  ｜  2026. 03. 16.", {
    x: 0.5, y: 5.25, w: 9.0, h: 0.25,
    fontFace: FONT.body, fontSize: 9, color: "777777",
    align: "center", margin: 0
  });
}

// ══════════════════════════════════════
// SLIDE 2 — 추진배경 (C-3: 3열 현황-문제-개선형)
// ══════════════════════════════════════
{
  const s = pres.addSlide();
  slideHeader(s, 1, "1. 추진배경",
    "연 1회 진단의 구조적 한계를 극복하고, AX 기반 실시간 Pulse Check 체계로 전환");

  // Column headers
  sectionLabel(s, 0.35, 1.15, 3.0, 0.28, "현행 연 1회 진단(LG Way Survey)의 구조적 한계");
  sectionLabel(s, 3.45, 1.15, 3.0, 0.28, "문제 드러내기");
  sectionLabel(s, 6.55, 1.15, 2.8, 0.28, "AX 기반 Pulse Check 전환 시 기대 효과");

  // ── Row 1 ──
  const problems = [
    {
      no: "①", title: "시간 지연 (Time Lag)",
      current: ["진단→분석→결과 공유 평균 1~2개월 소요", "이슈 발생 시점과 대응 시점 간극이 크다", "이탈·번아웃이 진행된 후에야 데이터 도달"],
      probLabel: "팀 이탈·번아웃 이미 진행 후 데이터 도달",
      effect: "Real-time Signal → 선제적 개입",
      effectDetail: ["월 1회 측정으로 이슈 발생 직후 HR·리더 감지", "번아웃·이탈 위험 부서 Risk Flag 조기 포착"]
    },
    {
      no: "②", title: "단면 스냅샷 (Static Snapshot)",
      current: ["조직 상태를 연 1회 '사진 한 장'으로만 본다", "계절·리더 교체 등 변동 요인 미반영", "몰입 지수 연중 어느 시점 붕괴인지 추적 불가"],
      probLabel: "연중 변화 원인 추론·추적 불가",
      effect: "Trend 추적 → 동적 조직 이해",
      effectDetail: ["Engagement Index 월별 궤적으로 변화 원인 추론", "HR 개입 효과를 데이터로 입증·피드백 선순환"]
    },
    {
      no: "③", title: "행동 연결 부재 (Action Gap)",
      current: ["결과 리포트 나오지만 리더 행동 변화 미연결", "전사 평균 수치 제시로 팀별 맞춤 솔루션 불가", '"좋은 데이터"가 "좋은 관리"로 자동 전환 안 됨'],
      probLabel: '"좋은 데이터"가 행동으로 자동 전환되지 않는다',
      effect: "Personalized Action → 계층 연결",
      effectDetail: ["구성원 개인 케어·리더 행동 가이드·경영진 Dashboard", "데이터가 리포트로 끝나지 않고 Action으로 연결"]
    },
  ];

  problems.forEach((p, i) => {
    const rowY = 1.48 + i * 1.35;
    // Left: current state
    s.addText([
      { text: `${p.no} ${p.title}`, options: { bold: true, breakLine: true, color: C.black } },
      ...p.current.map((c, ci) => ({
        text: "• " + c,
        options: { breakLine: ci < p.current.length - 1, color: C.darkGray, fontSize: 9 }
      }))
    ], {
      x: 0.35, y: rowY, w: 3.0, h: 1.25,
      fontFace: FONT.body, fontSize: 9.5, valign: "top",
      color: C.black
    });
    // Middle: black box problem statement
    blackBox(s, 3.45, rowY, 3.0, 0.32, `"${p.probLabel}"`, 8.5);
    s.addShape(pres.shapes.LINE, {
      x: 3.45, y: rowY + 0.38, w: 3.0, h: 0,
      line: { color: C.lightGray, width: 0.5 }
    });

    // Right: improvement
    s.addText([
      { text: `${p.no} ${p.effect}`, options: { bold: true, color: C.olive, breakLine: true } },
      ...p.effectDetail.map((e, ei) => ({
        text: "• " + e,
        options: { breakLine: ei < p.effectDetail.length - 1, color: C.darkGray, fontSize: 9 }
      }))
    ], {
      x: 6.55, y: rowY, w: 2.8, h: 1.25,
      fontFace: FONT.body, fontSize: 9.5, valign: "top"
    });

    // Row divider
    if (i < 2) {
      s.addShape(pres.shapes.LINE, {
        x: 0.35, y: rowY + 1.28, w: 9.0, h: 0,
        line: { color: C.lightGray, width: 0.5 }
      });
    }
  });
}

// ══════════════════════════════════════
// SLIDE 3 — EX Intelligence 정의 & 지향점
// ══════════════════════════════════════
{
  const s = pres.addSlide();
  slideHeader(s, 2, "2. EX Intelligence : AX 기반 일하는 방식의 전환",
    "SDT × LMX × POS 기반 구성원 인식·행동을 데이터로 읽고, AI로 분석하며, 즉각적 솔루션으로 연결하는 상시 진단 체계");

  // Definition box
  s.addShape(pres.shapes.RECTANGLE, {
    x: 0.35, y: 1.15, w: 9.3, h: 0.42,
    fill: { color: "F0F0F0" }, line: { color: "CCCCCC", width: 0.5 }
  });
  s.addText([
    { text: "EX Intelligence", options: { bold: true, color: C.olive } },
    { text: "는 구성원의 인식·행동을 데이터로 읽고, AI로 분석하며, 즉각적인 솔루션으로 연결하는 ", options: { color: C.black } },
    { text: "AX 기반 상시 진단 체계", options: { bold: true, color: C.black } },
    { text: "입니다.", options: { color: C.black } },
  ], {
    x: 0.45, y: 1.15, w: 9.1, h: 0.42,
    fontFace: FONT.body, fontSize: 11, valign: "middle"
  });

  // 3 transformation cards
  const cards = [
    {
      num: "①", title: "판단 근거의 전환", arrow: "감(感) → 데이터",
      items: ["직관을 데이터로 검증", "모호한 '느낌'을 확실한 '근거'로 전환", "사후 수습에서 벗어나 위험 신호 사전 감지"]
    },
    {
      num: "②", title: "실행으로 전환", arrow: "보고 → 행동",
      items: ["보고서 작성 대신 다음 날의 변화로 직결", "즉시 실행 가능한 Actionable Insight 제공", "HR 개입 효과를 데이터로 입증"]
    },
    {
      num: "③", title: "역할의 전환", arrow: "관리 → 인텔리전스",
      items: ["선제적 대응 체계 구축", "구성원·리더·경영진 계층별 맞춤 연결", "데이터 축적 → AI 고도화 → 신뢰 형성"]
    },
  ];

  cards.forEach((c, i) => {
    const cx = 0.35 + i * 3.12;
    const cw = 2.95;
    // Card background
    s.addShape(pres.shapes.RECTANGLE, {
      x: cx, y: 1.65, w: cw, h: 2.8,
      fill: { color: C.white },
      line: { color: C.lightGray, width: 0.8 },
      shadow: { type: "outer", blur: 4, offset: 1, angle: 135, color: "000000", opacity: 0.08 }
    });
    // Number circle
    s.addShape(pres.shapes.OVAL, {
      x: cx + 0.12, y: 1.72, w: 0.38, h: 0.38,
      fill: { color: C.black }, line: { color: C.black }
    });
    s.addText(c.num, {
      x: cx + 0.12, y: 1.72, w: 0.38, h: 0.38,
      fontFace: FONT.title, fontSize: 10, bold: true, color: C.white,
      align: "center", valign: "middle", margin: 0
    });
    // Title
    s.addText(c.title, {
      x: cx + 0.56, y: 1.72, w: cw - 0.65, h: 0.38,
      fontFace: FONT.title, fontSize: 11, bold: true, color: C.black,
      valign: "middle", margin: 0
    });
    // Arrow label (black bg)
    blackBox(s, cx + 0.12, 2.17, cw - 0.24, 0.28, c.arrow, 10);
    // Items
    s.addText(c.items.map((item, ii) => ({
      text: "• " + item,
      options: { breakLine: ii < c.items.length - 1, color: C.darkGray }
    })), {
      x: cx + 0.12, y: 2.52, w: cw - 0.24, h: 1.85,
      fontFace: FONT.body, fontSize: 9.5, valign: "top"
    });
  });

  // Bottom improvement box
  s.addShape(pres.shapes.RECTANGLE, {
    x: 0.35, y: 4.53, w: 9.3, h: 0.58,
    fill: { color: C.darkGray }, line: { color: C.darkGray }
  });
  s.addText([
    { text: "운영 고도화의 선순환: ", options: { bold: true, color: C.white } },
    { text: "감에서 데이터로,  보고서에서 실행으로,  사후 대응에서 사전 예측으로 — ", options: { color: "DDDDDD" } },
    { text: "데이터 축적 → AI 고도화 → 신뢰 형성 → 데이터 품질 제고", options: { color: "BBBBBB", italic: true } },
  ], {
    x: 0.45, y: 4.53, w: 9.1, h: 0.58,
    fontFace: FONT.body, fontSize: 10, valign: "middle"
  });
}

// ══════════════════════════════════════
// SLIDE 4 — 작동원리 (C-7 프로세스 플로우)
// ══════════════════════════════════════
{
  const s = pres.addSlide();
  slideHeader(s, 3, "3. 작동원리 : \"Signal\"에서 \"Action\"까지",
    "Signal 수집 → AI 분석 → 계층별 Action Brief 자동 제공");

  const layers = [
    {
      no: "Layer 1", title: "신호 수집 (Monthly EX Pulse)",
      en: "Signal Collection",
      desc: "조직의 심박(心拍) 데이터를 정기적으로 확보하는 센서 가동",
      items: ["8개 핵심 문항", "eNPS (추천의향 지수)", "감정 온도계 (이모지)", "3분 이내 완료"],
      color: "F0F4FF"
    },
    {
      no: "Layer 2", title: "정보 분석 (AI & Analytics)",
      en: "Intelligence Analysis",
      desc: "단순 데이터에서 노이즈를 제거하고 유의미한 신호를 포착",
      items: ["Risk Flag 조기 경보 발동", "트렌드 급락 자동 탐지", "NLP 텍스트 감성 분석"],
      color: "F0FFF4"
    },
    {
      no: "Layer 3", title: "의사결정 브리핑 (Actionable Insight)",
      en: "Decision Brief",
      desc: "각 계층이 즉시 실행할 수 있는 맞춤형 정보와 가이드 제공",
      items: ["리더: 팀 리포트 + 코칭 가이드", "경영진: Pulse Dashboard", "구성원: 케어링 메시지"],
      color: "FFFAF0"
    },
  ];

  layers.forEach((l, i) => {
    const lx = 0.35 + i * 3.12;
    const lw = 2.95;
    const ly = 1.18;
    // Card
    s.addShape(pres.shapes.RECTANGLE, {
      x: lx, y: ly, w: lw, h: 3.9,
      fill: { color: l.color }, line: { color: C.lightGray, width: 0.8 }
    });
    // Top accent bar (colored)
    const accentColors = ["3B5BDB", "2F9E44", "E67700"];
    s.addShape(pres.shapes.RECTANGLE, {
      x: lx, y: ly, w: lw, h: 0.06,
      fill: { color: accentColors[i] }, line: { color: accentColors[i] }
    });
    // Layer badge
    s.addText(l.no, {
      x: lx + 0.1, y: ly + 0.1, w: 0.7, h: 0.22,
      fontFace: FONT.body, fontSize: 8, bold: true,
      color: accentColors[i], valign: "middle", margin: 0
    });
    // Title
    s.addText(l.title, {
      x: lx + 0.1, y: ly + 0.33, w: lw - 0.2, h: 0.36,
      fontFace: FONT.title, fontSize: 10.5, bold: true,
      color: C.black, valign: "middle", margin: 0
    });
    // English label
    s.addText(l.en, {
      x: lx + 0.1, y: ly + 0.7, w: lw - 0.2, h: 0.22,
      fontFace: FONT.body, fontSize: 9, italic: true,
      color: C.midGray, valign: "middle", margin: 0
    });
    // Description
    s.addText(l.desc, {
      x: lx + 0.1, y: ly + 0.95, w: lw - 0.2, h: 0.55,
      fontFace: FONT.body, fontSize: 8.5, color: C.darkGray,
      valign: "top", lineSpacingMultiple: 1.3
    });
    // Divider
    s.addShape(pres.shapes.LINE, {
      x: lx + 0.1, y: ly + 1.52, w: lw - 0.2, h: 0,
      line: { color: C.lightGray, width: 0.5 }
    });
    // Items
    s.addText(l.items.map((item, ii) => ({
      text: "• " + item,
      options: { breakLine: ii < l.items.length - 1, color: C.darkGray }
    })), {
      x: lx + 0.1, y: ly + 1.6, w: lw - 0.2, h: 1.4,
      fontFace: FONT.body, fontSize: 9.5, valign: "top"
    });

    // Arrow between cards
    if (i < 2) {
      s.addShape(pres.shapes.LINE, {
        x: lx + lw + 0.04, y: ly + 1.95, w: 0.09, h: 0,
        line: { color: C.darkGray, width: 1.5 }
      });
    }
  });

  // Bottom note
  s.addText("▶유첨. 영역별 측정 문항 설계(안)", {
    x: 0.35, y: 5.28, w: 3.5, h: 0.22,
    fontFace: FONT.body, fontSize: 8.5, color: C.olive, margin: 0
  });
}

// ══════════════════════════════════════
// SLIDE 5 — Health Check Process
// ══════════════════════════════════════
{
  const s = pres.addSlide();
  slideHeader(s, 4, "4. Health Check Process 제안",
    "월 1회 8문항 상시 진단 → AI 이상 판정 시 Deep Dive Interview 연동");

  // Top metrics
  const metrics = [
    { val: "8", unit: "개 문항", sub: "월 1회" },
    { val: "32", unit: "개 Sub문항", sub: "상시" },
    { val: "3", unit: "개 카테고리", sub: "" },
  ];
  metrics.forEach((m, i) => {
    const mx = 0.35 + i * 1.65;
