{"language": "javascript", "code": "const pptxgen = require("pptxgenjs");

const pres = new pptxgen();
pres.layout = 'LAYOUT_16x9';
pres.title = 'EX Intelligence 체계 구축';

// ─── Design tokens (EXG team style) ───
const C = {
  black:    "1A1A1A",
  darkGray: "444444",
  midGray:  "888888",
  lightGray:"E8E8E8",
  offWhite: "F5F5F5",
  white:    "FFFFFF",
  olive:    "4A7C59",   // accent green (bold keywords)
  red:      "CC0000",   // LG red (extreme emphasis)
  barColor: "222222",   // left vertical bar
  bgSlide:  "FFFFFF",
};

const FONT = {
  title:   "Malgun Gothic",
  body:    "Malgun Gothic",
};

// ─── Helpers ──────────────────────────
function slideHeader(slide, num, title, subtitle) {
  // Left vertical bar
  slide.addShape(pres.shapes.RECTANGLE, {
    x: 0.35, y: 0.28, w: 0.07, h: 0.55,
    fill: { color: C.barColor }, line: { color: C.barColor }
  });
  // Title
  slide.addText(title, {
    x: 0.50, y: 0.22, w: 8.8, h: 0.45,
    fontFace: FONT.title, fontSize: 18, bold: true,
    color: C.black, valign: "middle", margin: 0
  });
  // Subtitle
  if (subtitle) {
    slide.addText(subtitle, {
      x: 0.50, y: 0.72, w: 9.3, h: 0.30,
      fontFace: FONT.body, fontSize: 11, italic: true,
      color: C.darkGray, valign: "middle", margin: 0
    });
  }
  // Horizontal divider
  slide.addShape(pres.shapes.LINE, {
    x: 0.35, y: 1.07, w: 9.3, h: 0,
    line: { color: C.darkGray, width: 0.8 }
  });
  // Slide number
  slide.addText(`${num} / 8`, {
    x: 8.8, y: 5.30, w: 1.0, h: 0.22,
    fontFace: FONT.body, fontSize: 9, color: C.midGray,
    align: "right", margin: 0
  });
}

function blackBox(slide, x, y, w, h, text, fontSize = 9.5) {
  slide.addShape(pres.shapes.RECTANGLE, {
    x, y, w, h, fill: { color: C.black }, line: { color: C.black }
  });
  slide.addText(text, {
    x: x + 0.05, y, w: w - 0.1, h,
    fontFace: FONT.body, fontSize, color: C.white,
    bold: true, valign: "middle", align: "center", margin: 0
  });
}

function sectionLabel(slide, x, y, w, h, text) {
  slide.addShape(pres.shapes.RECTANGLE, {
    x, y, w, h, fill: { color: C.lightGray }, line: { color: C.lightGray }
  });
  slide.addText(text, {
    x, y, w, h,
    fontFace: FONT.body, fontSize: 9.5, bold: true,
    color: C.black, valign: "middle", align: "center", margin: 0
  });
}

function appendixBadge(slide, label) {
  slide.addShape(pres.shapes.RECTANGLE, {
    x: 8.5, y: 0.12, w: 1.3, h: 0.3,
    fill: { color: C.darkGray }, line: { color: C.darkGray }
  });
  slide.addText(label, {
    x: 8.5, y: 0.12, w: 1.3, h: 0.3,
    fontFace: FONT.body, fontSize: 8.5, color: C.white,
    bold: true, align: "center", valign: "middle", margin: 0
  });
}

function backLink(slide) {
  slide.addText("▶ 본문으로 돌아가기", {
    x: 0.35, y: 5.30, w: 2.5, h: 0.22,
    fontFace: FONT.body, fontSize: 8.5, color: C.midGray, margin: 0
  });
}

// ══════════════════════════════════════
// SLIDE 1 — 표지
// ══════════════════════════════════════
{
  const s = pres.addSlide();
  s.background = { color: "1A1A1A" };

  s.addText("『 EX Intelligence 』 체계 구축", {
    x: 0.8, y: 1.6, w: 8.4, h: 0.9,
