    color: C.white, align: "center", valign: "middle"
  });
  s.addText('"구성원 신호를 조직 성과로 전환하는 AX 기반 상시 진단 체계"', {
    x: 0.8, y: 2.55, w: 8.4, h: 0.4,
    fontFace: FONT.body, fontSize: 14, italic: true,
    color: "BBBBBB", align: "center", valign: "middle"
  });
  // Divider
  s.addShape(pres.shapes.LINE, {
    x: 2.5, y: 3.1, w: 5.0, h: 0,
    line: { color: "444444", width: 0.8 }
