  sectionLabel(s, 0.35, 1.15, 3.0, 0.28, "현행 연 1회 진단(LG Way Survey)의 구조적 한계");
  sectionLabel(s, 3.45, 1.15, 3.0, 0.28, "문제 드러내기");
  sectionLabel(s, 6.55, 1.15, 2.8, 0.28, "AX 기반 Pulse Check 전환 시 기대 효과");

  // ── Row 1 ──
  const problems = [
    {
      no: "①", title: "시간 지연 (Time Lag)",
      current: ["진단→분석→결과 공유 평균 1~2개월 소요", "이슈 발생 시점과 대응 시점 간극이 크다", "이탈·번아웃이 진행된 후에야 데이터 도달"],
      probLabel: "팀 이탈·번아웃 이미 진행 후 데이터 도달",
      effect: "Real-time Signal → 선제적 개입",
      effectDetail: ["월 1회 측정으로 이슈 발생 직후 HR·리더 감지", "번아웃·이탈 위험 부서 Risk Flag 조기 포착"]
    },
    {
      no: "②", title: "단면 스냅샷 (Static Snapshot)",
      current: ["조직 상태를 연 1회 '사진 한 장'으로만 본다", "계절·리더 교체 등 변동 요인 미반영", "몰입 지수 연중 어느 시점 붕괴인지 추적 불가"],
      probLabel: "연중 변화 원인 추론·추적 불가",
      effect: "Trend 추적 → 동적 조직 이해",
      effectDetail: ["Engagement Index 월별 궤적으로 변화 원인 추론", "HR 개입 효과를 데이터로 입증·피드백 선순환"]
    },
    {
      no: "③", title: "행동 연결 부재 (Action Gap)",
      current: ["결과 리포트 나오지만 리더 행동 변화 미연결", "전사 평균 수치 제시로 팀별 맞춤 솔루션 불가", '"좋은 데이터"가 "좋은 관리"로 자동 전환 안 됨'],
      probLabel: '"좋은 데이터"가 행동으로 자동 전환되지 않는다',
      effect: "Personalized Action → 계층 연결",
